// ====== Prepare Data: Combine 4 services + Static Data Stats + Config ======

// Get services from the 4 HTTP nodes
const srv01 = $('frontend_templates2').first().json;
const srv02 = $('frontend_custom.2').first().json;
const srv03 = $('fullstack2').first().json;
const srv04 = $('ai_business_solutions2').first().json;
const services = [srv01, srv02, srv03, srv04];

// Load Stats from n8n Static Data (auto-persists between executions)
const staticData = $getWorkflowStaticData('global');
if (!staticData.stats) {
  staticData.stats = {
    total_posts: 0,
    service_rotation_index: 0,
    style_rotation_index: 0,
    package_rotation_index: 0,
    last_20_posts: [],
    feature_usage: {}
  };
}

// Embedded config (no external file needed)
const config = {
  post_styles: [
    {
      id: 'success_story',
      name_ar: 'قصة نجاح',
      prompt_instruction: 'اكتب المنشور كقصة نجاح لزبون استخدم خدمتنا. ابدأ بمشكلة كان يعانيها، ثم كيف حلّيناها، ثم النتيجة المبهرة. استخدم أسلوب حواري ومشوّق.'
    },
    {
      id: 'problem_solution',
      name_ar: 'مشكلة وحل',
      prompt_instruction: 'ابدأ بطرح مشكلة شائعة يعانيها أصحاب الأعمال، ثم اعرض الحل الذي نقدمه مع الميزات التقنية. اجعل القارئ يشعر بأنه يحتاج هذا الحل فوراً.'
    },
    {
      id: 'comparison',
      name_ar: 'مقارنة: بدون خدمتنا vs مع خدمتنا',
      prompt_instruction: 'اكتب المنشور كمقارنة بين الحالة بدون خدمتنا (المشاكل، التكلفة العالية، الوقت الضائع) والحالة مع خدمتنا (الحلول، التوفير، السرعة). استخدم إيموجي ❌ و ✅.'
    },
    {
      id: 'stats_facts',
      name_ar: 'أرقام وإحصائيات',
      prompt_instruction: 'ابدأ بأرقام وإحصائيات مقنعة عن المجال. ثم اربط هذه الأرقام بخدمتنا وكيف تساعد الزبون. اجعل الأرقام بارزة ومؤثرة.'
    }
  ],
  ai_instructions: {
    general_rules: [
      'اكتب بالعربية الفصحى البسيطة مع لمسة دارجة جزائرية خفيفة',
      'طول المنشور: 150-300 كلمة',
      'استخدم إيموجي بشكل مناسب (3-6 إيموجي)',
      'اختم المنشور بدعوة واضحة للتواصل (CTA)',
      'اذكر السعر بطريقة جذابة (يبدأ من...)',
      'لا تذكر اسم المنافسين',
      'استخدم 3-5 هاشتاقات مناسبة في النهاية'
    ],
    brand_voice: 'أسلوب احترافي ومحترم لكن قريب من الناس، يجمع بين الخبرة التقنية والبساطة في الشرح'
  },
  facebook: {
    page_id: 'YOUR_PAGE_ID'
  }
};

return [{ json: { services, stats: staticData.stats, config } }];

// ====== SMART SELECTOR — Brain of the system ======
const { services, config, stats } = $input.first().json;

// ---- 1. Choose Service (rotation) ----
const serviceOrder = ['SRV-01', 'SRV-02', 'SRV-03', 'SRV-04'];
const srvIndex = stats.service_rotation_index % serviceOrder.length;
const targetServiceId = serviceOrder[srvIndex];
let selectedService = services.find(s => s.service_id === targetServiceId);
if (!selectedService) selectedService = services[0];

// ---- 2. Choose Package (rotation through tiers) ----
let packages;
let solutionName = null;
if (selectedService.packages) {
  packages = selectedService.packages;
} else if (selectedService.solutions) {
  // SRV-04 has solutions with sub-packages
  const solIndex = stats.package_rotation_index % selectedService.solutions.length;
  const selectedSolution = selectedService.solutions[solIndex];
  solutionName = selectedSolution.solution_name;
  packages = selectedSolution.packages;
}

const pkgIndex = stats.package_rotation_index % packages.length;
const selectedPackage = packages[pkgIndex];

// ---- 3. Choose Features (avoid last 20 posts) ----
const recentFeatures = new Set();
for (const post of (stats.last_20_posts || [])) {
  if (post.features) post.features.forEach(f => recentFeatures.add(f));
}

const allFeatures = [];
for (const key of Object.keys(selectedPackage.features || {})) {
  const feats = selectedPackage.features[key];
  if (Array.isArray(feats)) {
    feats.forEach(f => {
      if (typeof f === 'string' && !f.startsWith('كل ')) {
        allFeatures.push({ text: f, category: key });
      }
    });
  }
}

let available = allFeatures.filter(f => !recentFeatures.has(f.text));
if (available.length < 3) available = allFeatures;

const shuffled = available.sort(() => Math.random() - 0.5);
const count = Math.floor(Math.random() * 3) + 3;
const selectedFeatures = shuffled.slice(0, count);

// ---- 4. Choose Post Style (rotation) ----
const styles = config.post_styles;
const styleIndex = stats.style_rotation_index % styles.length;
const selectedStyle = styles[styleIndex];

// ---- 5. Keywords ----
const keywords = (selectedService.publishing_keywords || []).sort(() => Math.random() - 0.5).slice(0, 4);

// ---- 6. Build prompt text for AI ----
const svcName = selectedService.service_name;
const svcDesc = selectedService.description;
const pkgName = selectedPackage.package_name;
const pkgNameEn = selectedPackage.package_name_en || '';
const pkgBadge = selectedPackage.badge || '';
const price = selectedPackage.price;
const delivery = selectedPackage.delivery_days;
const audience = (selectedService.target_audience || []).join(', ');

const featuresText = selectedFeatures.map((f, i) => (i + 1) + '. ' + f.text).join('\n');

const userPrompt = `اكتب منشور فايسبوك احترافي.

الخدمة: ${svcName}
الوصف: ${svcDesc}${solutionName ? '\nالحل: ' + solutionName : ''}
الباقة: ${pkgName} (${pkgNameEn})${pkgBadge ? ' — ' + pkgBadge : ''}
السعر: يبدأ من ${price.base} ${price.currency}
التسليم: ${delivery} يوم عمل

الميزات المختارة للتركيز عليها:
${featuresText}

أسلوب الكتابة: ${selectedStyle.name_ar}
التعليمات: ${selectedStyle.prompt_instruction}

الكلمات المفتاحية (أدرجها بشكل طبيعي): ${keywords.join(', ')}

الجمهور المستهدف: ${audience}`;

const systemPrompt = `أنت خبير تسويق رقمي متخصص في كتابة منشورات فايسبوك بالعربية. تكتب محتوى يجذب أصحاب الأعمال والشركات. ${config.ai_instructions.brand_voice}. القواعد: ${config.ai_instructions.general_rules.join(' | ')}`;

return [{ json: {
  selected_service: {
    id: selectedService.service_id,
    name: svcName,
    name_en: selectedService.service_name_en,
    description: svcDesc,
    target_audience: selectedService.target_audience,
    solution_name: solutionName
  },
  selected_package: {
    id: selectedPackage.package_id,
    name: pkgName,
    name_en: pkgNameEn,
    badge: pkgBadge,
    price: price,
    delivery_days: delivery
  },
  selected_features: selectedFeatures.map(f => f.text),
  post_style: selectedStyle,
  keywords,
  user_prompt: userPrompt,
  system_prompt: systemPrompt,
  new_rotation: {
    service_rotation_index: srvIndex + 1,
    style_rotation_index: styleIndex + 1,
    package_rotation_index: pkgIndex + 1
  },
  config
} }];

// ====== Extract Draft: Normalize Cerebras output ======
// Community nodes may output in different fields, this handles all cases
const input = $input.first().json;
const draft = input.response || input.text || input.output || input.content ||
              input.message || input.result ||
              (input.choices && input.choices[0] && input.choices[0].message && input.choices[0].message.content) ||
              JSON.stringify(input);

return [{ json: { draft } }];

// ====== Extract Final Post: Normalize GH Models output ======
const input = $input.first().json;
const final_post = input.response || input.text || input.output || input.content ||
                   input.message || input.result ||
                   (input.choices && input.choices[0] && input.choices[0].message && input.choices[0].message.content) ||
                   JSON.stringify(input);

return [{ json: { final_post } }];

// ====== Update Stats in n8n Static Data ======
const staticData = $getWorkflowStaticData('global');
const selector = $('Smart Selector2').first().json;
const fbResponse = $input.first().json;

if (!staticData.stats) {
  staticData.stats = {
    total_posts: 0,
    service_rotation_index: 0,
    style_rotation_index: 0,
    package_rotation_index: 0,
    last_20_posts: [],
    feature_usage: {}
  };
}

const stats = staticData.stats;
stats.total_posts += 1;

// Update rotations
stats.service_rotation_index = selector.new_rotation.service_rotation_index;
stats.style_rotation_index = selector.new_rotation.style_rotation_index;
stats.package_rotation_index = selector.new_rotation.package_rotation_index;

// Add to history (keep last 20)
stats.last_20_posts.unshift({
  post_number: stats.total_posts,
  service_id: selector.selected_service.id,
  service_name: selector.selected_service.name,
  package_id: selector.selected_package.id,
  package_name: selector.selected_package.name,
  features: selector.selected_features,
  style: selector.post_style.id,
  facebook_post_id: fbResponse.id || fbResponse.final_post ? 'test' : 'unknown',
  published_at: new Date().toISOString()
});
if (stats.last_20_posts.length > 20) {
  stats.last_20_posts = stats.last_20_posts.slice(0, 20);
}

// Update feature usage
for (const f of selector.selected_features) {
  stats.feature_usage[f] = (stats.feature_usage[f] || 0) + 1;
}

stats.last_updated = new Date().toISOString();
// Static Data auto-saves — no fs.writeFile needed!

return [{ json: {
  status: 'success',
  post_number: stats.total_posts,
  service: selector.selected_service.name,
  package_name: selector.selected_package.name,
  features_count: selector.selected_features.length,
  style: selector.post_style.name_ar,
  facebook_post_id: fbResponse.id || 'test'
} }];

// ====== Log Result ======
const result = $input.first().json;
const timestamp = new Date().toISOString();

return [{ json: {
  ...result,
  timestamp,
  log: `✅ Post #${result.post_number} | ${result.service} | ${result.package_name} | ${result.style}`
} }];

// ====== Prepare Data: Combine 4 services + Static Data + Config ======
// Sequential chain guarantees all HTTP nodes have completed
const srv01 = $('Fetch Templates').first().json;
const srv02 = $('Fetch Custom').first().json;
const srv03 = $('Fetch Fullstack').first().json;
const srv04 = $('Fetch AI Solutions').first().json;
const services = [srv01, srv02, srv03, srv04];

// Load Stats from n8n Static Data (auto-persists)
const staticData = $getWorkflowStaticData('global');
if (!staticData.stats) {
  staticData.stats = {
    total_posts: 0,
    service_rotation_index: 0,
    style_rotation_index: 0,
    package_rotation_index: 0,
    last_20_posts: [],
    feature_usage: {}
  };
}

const config = {
  post_styles: [
    { id: 'success_story', name_ar: 'قصة نجاح', prompt_instruction: 'اكتب المنشور كقصة نجاح لزبون استخدم خدمتنا. ابدأ بمشكلة كان يعانيها، ثم كيف حلّيناها، ثم النتيجة المبهرة. استخدم أسلوب حواري ومشوّق.' },
    { id: 'problem_solution', name_ar: 'مشكلة وحل', prompt_instruction: 'ابدأ بطرح مشكلة شائعة يعانيها أصحاب الأعمال، ثم اعرض الحل الذي نقدمه مع الميزات التقنية. اجعل القارئ يشعر بأنه يحتاج هذا الحل فوراً.' },
    { id: 'comparison', name_ar: 'مقارنة: بدون خدمتنا vs مع خدمتنا', prompt_instruction: 'اكتب كمقارنة بين الحالة بدون خدمتنا والحالة مع خدمتنا. استخدم إيموجي ❌ و ✅.' },
    { id: 'stats_facts', name_ar: 'أرقام وإحصائيات', prompt_instruction: 'ابدأ بأرقام وإحصائيات مقنعة عن المجال. ثم اربطها بخدمتنا. اجعل الأرقام بارزة ومؤثرة.' }
  ],
  ai_instructions: {
    general_rules: ['اكتب بالعربية الفصحى البسيطة مع لمسة دارجة جزائرية خفيفة', 'طول المنشور: 150-300 كلمة', 'استخدم إيموجي (3-6)', 'اختم بدعوة للتواصل CTA', 'اذكر السعر (يبدأ من...)', 'لا تذكر المنافسين', '3-5 هاشتاقات في النهاية'],
    brand_voice: 'أسلوب احترافي ومحترم لكن قريب من الناس، يجمع بين الخبرة التقنية والبساطة في الشرح'
  },
  facebook: { page_id: 'YOUR_PAGE_ID' }
};

return [{ json: { services, stats: staticData.stats, config } }];

// ====== SMART SELECTOR — Brain of the system ======
const { services, config, stats } = $input.first().json;

// 1. Choose Service (rotation)
const serviceOrder = ['SRV-01', 'SRV-02', 'SRV-03', 'SRV-04'];
const srvIndex = stats.service_rotation_index % serviceOrder.length;
let selectedService = services.find(s => s.service_id === serviceOrder[srvIndex]) || services[0];

// 2. Choose Package (rotation)
let packages, solutionName = null;
if (selectedService.packages) {
  packages = selectedService.packages;
} else if (selectedService.solutions) {
  const solIndex = stats.package_rotation_index % selectedService.solutions.length;
  const sol = selectedService.solutions[solIndex];
  solutionName = sol.solution_name;
  packages = sol.packages;
}
const pkgIndex = stats.package_rotation_index % packages.length;
const selectedPackage = packages[pkgIndex];

// 3. Choose Features (avoid last 20)
const recentFeatures = new Set();
for (const post of (stats.last_20_posts || [])) {
  if (post.features) post.features.forEach(f => recentFeatures.add(f));
}
const allFeatures = [];
for (const key of Object.keys(selectedPackage.features || {})) {
  const feats = selectedPackage.features[key];
  if (Array.isArray(feats)) feats.forEach(f => {
    if (typeof f === 'string' && !f.startsWith('كل ')) allFeatures.push({ text: f, category: key });
  });
}
let available = allFeatures.filter(f => !recentFeatures.has(f.text));
if (available.length < 3) available = allFeatures;
const shuffled = available.sort(() => Math.random() - 0.5);
const selectedFeatures = shuffled.slice(0, Math.floor(Math.random() * 3) + 3);

// 4. Post Style (rotation)
const styleIndex = stats.style_rotation_index % config.post_styles.length;
const selectedStyle = config.post_styles[styleIndex];

// 5. Keywords
const keywords = (selectedService.publishing_keywords || []).sort(() => Math.random() - 0.5).slice(0, 4);

// 6. Build prompts
const svcName = selectedService.service_name;
const svcDesc = selectedService.description;
const pkgName = selectedPackage.package_name;
const pkgEn = selectedPackage.package_name_en || '';
const pkgBadge = selectedPackage.badge || '';
const price = selectedPackage.price;
const delivery = selectedPackage.delivery_days;
const audience = (selectedService.target_audience || []).join(', ');
const featText = selectedFeatures.map((f, i) => (i+1) + '. ' + f.text).join('\n');

const user_prompt = `اكتب منشور فايسبوك احترافي.\n\nالخدمة: ${svcName}\nالوصف: ${svcDesc}${solutionName ? '\nالحل: ' + solutionName : ''}\nالباقة: ${pkgName} (${pkgEn})${pkgBadge ? ' — ' + pkgBadge : ''}\nالسعر: يبدأ من ${price.base} ${price.currency}\nالتسليم: ${delivery} يوم عمل\n\nالميزات المختارة:\n${featText}\n\nأسلوب: ${selectedStyle.name_ar}\nتعليمات: ${selectedStyle.prompt_instruction}\n\nكلمات مفتاحية: ${keywords.join(', ')}\n\nالجمهور: ${audience}`;

const system_prompt = `أنت خبير تسويق رقمي متخصص في كتابة منشورات فايسبوك بالعربية. ${config.ai_instructions.brand_voice}. القواعد: ${config.ai_instructions.general_rules.join(' | ')}`;

return [{ json: {
  selected_service: { id: selectedService.service_id, name: svcName, name_en: selectedService.service_name_en, description: svcDesc, target_audience: selectedService.target_audience, solution_name: solutionName },
  selected_package: { id: selectedPackage.package_id, name: pkgName, name_en: pkgEn, badge: pkgBadge, price, delivery_days: delivery },
  all_packages: packages,
  selected_features: selectedFeatures.map(f => f.text),
  post_style: selectedStyle,
  keywords,
  user_prompt,
  system_prompt,
  new_rotation: { service_rotation_index: srvIndex + 1, style_rotation_index: styleIndex + 1, package_rotation_index: pkgIndex + 1 },
  config
} }];

// ====== Generate HTML Comparison Table for the selected service ======
const selector = $input.first().json;
const packages = selector.all_packages;
const svcName = selector.selected_service.name;
const svcDesc = selector.selected_service.description;

// Random themes for variation
const themes = [
  { bg1: '#0f0c29', bg2: '#302b63', bg3: '#24243e', hl: '#00d4aa', cardBg: 'rgba(255,255,255,0.05)', midBg: 'rgba(0,212,170,0.08)' }, // Dark Teal
  { bg1: '#141e30', bg2: '#243b55', bg3: '#141e30', hl: '#ffa700', cardBg: 'rgba(255,255,255,0.05)', midBg: 'rgba(255,167,0,0.08)' }, // Deep Blue & Gold
  { bg1: '#232526', bg2: '#414345', bg3: '#232526', hl: '#ff4b2b', cardBg: 'rgba(255,255,255,0.05)', midBg: 'rgba(255,75,43,0.08)' }, // Charcoal & Red
  { bg1: '#111', bg2: '#222', bg3: '#111', hl: '#8a2be2', cardBg: 'rgba(255,255,255,0.03)', midBg: 'rgba(138,43,226,0.08)' }, // Midnight Purple
  { bg1: '#0b132b', bg2: '#1c2541', bg3: '#0b132b', hl: '#5bc0be', cardBg: 'rgba(255,255,255,0.05)', midBg: 'rgba(91,192,190,0.08)' } // Cyber Ocean
];
const randFactor = selector.new_rotation.service_rotation_index + selector.new_rotation.package_rotation_index + selector.new_rotation.style_rotation_index;
const theme = themes[randFactor % themes.length];

function getFeatures(pkg) {
  const feats = pkg.features || {};
  let techFeats = [];
  if (feats.technical) techFeats = feats.technical;
  else if (feats.technical_security) techFeats = feats.technical_security;
  else if (feats.technology_stack) techFeats = feats.technology_stack;
  else if (feats.backend_features) techFeats = feats.backend_features;
  else if (feats.security_performance) techFeats = feats.security_performance;

  let genFeats = [];
  if (feats.general) genFeats = feats.general;
  else if (feats.business_features) genFeats = feats.business_features;

  const general = (genFeats.filter(f => typeof f === 'string' && !f.startsWith('كل ')).sort(() => Math.random() - 0.5)).slice(0, 5);
  const technical = (techFeats.filter(f => typeof f === 'string' && !f.startsWith('كل ')).sort(() => Math.random() - 0.5)).slice(0, 3);
  const notIncl = (feats.not_included || []).slice(0, 2);

  return { general, technical, notIncl };
}

let cardsHtml = '';
packages.forEach((pkg, idx) => {
  const isMid = idx === 1 || (packages.length === 2 && idx === 1);
  const border = isMid ? theme.hl : 'rgba(255,255,255,0.12)';
  const bg = isMid ? theme.midBg : theme.cardBg;
  const scale = isMid ? 'transform:scale(1.04);z-index:2;box-shadow: 0 15px 35px rgba(0,0,0,0.3);' : 'opacity: 0.95;';
  const { general, technical, notIncl } = getFeatures(pkg);
  const rev = typeof pkg.revisions === 'number' ? pkg.revisions + ' مراجعات' : (pkg.revisions || '');

  cardsHtml += `<div style="flex:1;background:${bg};border-radius:20px;padding:30px 20px;border:2px solid ${border};${scale}position:relative;">`;
  if (pkg.badge) cardsHtml += `<div style="position:absolute;top:-12px;left:50%;transform:translateX(-50%);white-space:nowrap;background:${theme.hl};color:#000;padding:4px 16px;border-radius:12px;font-size:12px;font-weight:bold;box-shadow:0 4px 10px rgba(0,0,0,0.2);">${pkg.badge}</div>`;
  else cardsHtml += `<div style="height:12px;"></div>`;

  cardsHtml += `<h3 style="text-align:center;margin:15px 0 4px;font-size:20px;color:#fff;">${pkg.package_name}</h3>`;
  cardsHtml += `<p style="text-align:center;color:#999;font-size:12px;margin:0 0 16px;">${pkg.package_name_en || ''}</p>`;
  cardsHtml += `<div style="text-align:center;margin-bottom:12px;"><span style="font-size:42px;font-weight:900;color:${theme.hl};">$${pkg.price.base}+</span></div>`;
  cardsHtml += `<div style="text-align:center;font-size:12px;color:#bbb;margin-bottom:16px;">⏱ التنفيذ: ${pkg.delivery_days} أيام | 🔄 ${rev}</div>`;
  cardsHtml += '<hr style="border:none;border-top:1px dashed rgba(255,255,255,0.15);margin:16px 0;">';

  general.forEach(f => { cardsHtml += `<p style="font-size:13px;line-height:1.5;margin:8px 0;color:#eee;">✅ ${f}</p>`; });
  technical.forEach(f => { cardsHtml += `<p style="font-size:13px;line-height:1.5;margin:8px 0;color:${theme.hl};opacity:0.9;">⚙️ ${f}</p>`; });
  notIncl.forEach(f => { cardsHtml += `<p style="font-size:13px;line-height:1.5;margin:8px 0;color:#666;text-decoration:line-through;">❌ ${f}</p>`; });
  cardsHtml += '</div>';
});

const html = `<div style="font-family:'Segoe UI',Tahoma,sans-serif;direction:rtl;width:1080px;min-height:500px;padding:50px 60px;background:linear-gradient(135deg,${theme.bg1} 0%,${theme.bg2} 50%,${theme.bg3} 100%);color:#fff;border-radius:24px;">
  <div style="text-align:center;margin-bottom:40px;">
    <h1 style="font-size:34px;margin:0 0 12px;color:${theme.hl};text-shadow: 0 2px 4px rgba(0,0,0,0.3);">${svcName}</h1>
    <p style="color:#aaa;font-size:16px;max-width:800px;margin:0 auto;line-height:1.6;">${svcDesc}</p>
  </div>
  <div style="display:flex;gap:20px;align-items:center;">${cardsHtml}</div>
  <div style="text-align:center;margin-top:40px;"><p style="color:#ddd;font-size:15px;font-weight:bold;background:rgba(0,0,0,0.2);display:inline-block;padding:10px 24px;border-radius:20px;border:1px solid rgba(255,255,255,0.1);">📩 تواصل معنا الآن للحصول على عرض تقني وتجاري مخصص لمشروعك</p></div>
</div>`;

return [{ json: { ...selector, table_html: html } }];

// ====== Extract Draft: Normalize Cerebras output ======
const input = $input.first().json;
const draft = input.response || input.text || input.output || input.content || input.message || input.result || (input.choices && input.choices[0] && input.choices[0].message && input.choices[0].message.content) || JSON.stringify(input);
return [{ json: { draft } }];

// ====== Extract Final Post: Normalize GH Models output ======
const input = $input.first().json;
const final_post = input.response || input.text || input.output || input.content || input.message || input.result || (input.choices && input.choices[0] && input.choices[0].message && input.choices[0].message.content) || JSON.stringify(input);
return [{ json: { final_post } }];

// ====== Update Stats in Static Data ======
const staticData = $getWorkflowStaticData('global');
const selector = $('Smart Selector').first().json;
const fbResponse = $input.first().json;

if (!staticData.stats) {
  staticData.stats = { total_posts: 0, service_rotation_index: 0, style_rotation_index: 0, package_rotation_index: 0, last_20_posts: [], feature_usage: {} };
}
const stats = staticData.stats;
stats.total_posts += 1;
stats.service_rotation_index = selector.new_rotation.service_rotation_index;
stats.style_rotation_index = selector.new_rotation.style_rotation_index;
stats.package_rotation_index = selector.new_rotation.package_rotation_index;

stats.last_20_posts.unshift({
  post_number: stats.total_posts,
  service_id: selector.selected_service.id,
  service_name: selector.selected_service.name,
  package_id: selector.selected_package.id,
  package_name: selector.selected_package.name,
  features: selector.selected_features,
  style: selector.post_style.id,
  published_at: new Date().toISOString()
});
if (stats.last_20_posts.length > 20) stats.last_20_posts = stats.last_20_posts.slice(0, 20);
for (const f of selector.selected_features) stats.feature_usage[f] = (stats.feature_usage[f] || 0) + 1;
stats.last_updated = new Date().toISOString();

return [{ json: { status: 'success', post_number: stats.total_posts, service: selector.selected_service.name, package_name: selector.selected_package.name, features_count: selector.selected_features.length, style: selector.post_style.name_ar } }];
